css:
.vbes-cta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 32px;
  background: {{bg_color}};
  padding: 48px 40px;
  border-radius: 12px;
}
.vbes-cta__content {
  flex: 1;
}
.vbes-cta__heading {
  font-size: 1.75rem;
  font-weight: 700;
  color: #fff;
  margin: 0 0 8px;
}
.vbes-cta__text {
  font-size: 1rem;
  color: rgba(255,255,255,0.85);
  margin: 0;
  line-height: 1.6;
}
.vbes-cta__btn {
  display: inline-block;
  white-space: nowrap;
  padding: 14px 32px;
  background: #fff;
  color: {{bg_color}};
  text-decoration: none;
  border-radius: 6px;
  font-weight: 600;
  font-size: 1rem;
  transition: transform 0.2s;
}
.vbes-cta__btn:hover {
  transform: translateY(-2px);
}
@media (max-width: 768px) {
  .vbes-cta {
    flex-direction: column;
    text-align: center;
    padding: 32px 24px;
  }
}
